sql:
SELECT business_purpose
  FROM data_collection
  WHERE collected = 'YES';

SELECT description
FROM data_categories
WHERE category_name = 'Personal Information';

SELECT category_name
FROM data_categories
WHERE category_id = 1;

SELECT COUNT(DISTINCT user_id) AS consent_count
FROM user_consent
WHERE consent_status = 'OPT_IN';

SELECT name
FROM third_parties
WHERE sharing_purpose = 'Marketing';

SELECT MAX(access_date)
FROM data_access
WHERE user_id = 1;

external_knowledge:
- Most recently shared implies the latest data sharing activity based on the sharing date; 
- Within its retention period means the data's sharing date is on or after the retention start date and on or before the retention end date, or the retention end date is null (indicating no end to the retention period); 
- Has not been deleted implies the data's sharing date is either before its deletion date or there is no deletion date recorded.

sql:
SELECT category_name
FROM data_categories
WHERE last_updated = (SELECT MAX(last_updated) FROM data_categories);

external_knowledge:
- The year 2023 is the timeframe of interest for data sharing activities; 
- Data retention periods are measured in months; 
- The threshold of "more than 6 months" for retention periods is considered significant in this context.

sql:
SELECT COUNT(*) AS recent_updates
FROM data_categories
WHERE last_updated >= DATE('now', '-30 days');
